static inline void fifo_rx_init(word_t *r) {
    word_t i = 0ULL;
    for (i = 0ULL; i < FIFO_RX_REG_COUNT; i = i + 1ULL) { r[i] = 0ULL; }
    r[FIFO_RX_ONE] = 1ULL;
    r[FIFO_RX_ZERO] = 0ULL;
    r[FIFO_RX_SLOT_MASK] = 511ULL;
    r[FIFO_RX_TOP2_MASK] = 768ULL;
    r[FIFO_RX_LMASK_1] = 9223372036854775807ULL;
}

/* fifo_rx_tick: one clock edge. READ inputs as const locals,
 * COMPUTE via cells (no native add/sub/mul on data), WRITE every register. */
static inline void fifo_rx_tick(word_t *r) {
    /* READ phase — pre-read every consumed register value. */
    const word_t fifo_power = r[FIFO_RX_FIFO_POWER];
    const word_t fifo_rd_en = r[FIFO_RX_FIFO_RD_EN];
    const word_t nic_seam_strobe = r[FIFO_RX_NIC_SEAM_STROBE];
    const word_t nic_seam_bid_px = r[FIFO_RX_NIC_SEAM_BID_PX];
    const word_t nic_seam_ask_px = r[FIFO_RX_NIC_SEAM_ASK_PX];
    const word_t nic_seam_time = r[FIFO_RX_NIC_SEAM_TIME];
    const word_t nic_seam_src_time = r[FIFO_RX_NIC_SEAM_SRC_TIME];
    const word_t nic_seam_symbol = r[FIFO_RX_NIC_SEAM_SYMBOL];
    const word_t nic_seam_pip = r[FIFO_RX_NIC_SEAM_PIP];
    const word_t nic_seam_commission = r[FIFO_RX_NIC_SEAM_COMMISSION];
    const word_t nic_seam_seq = r[FIFO_RX_NIC_SEAM_SEQ];
    const word_t one = r[FIFO_RX_ONE];
    const word_t zero = r[FIFO_RX_ZERO];
    const word_t slot_mask = r[FIFO_RX_SLOT_MASK];
    const word_t top2_mask = r[FIFO_RX_TOP2_MASK];
    const word_t lmask_1 = r[FIFO_RX_LMASK_1];
    const word_t fifo_ticks = r[FIFO_RX_FIFO_TICKS];
    const word_t fifo_wr_bin = r[FIFO_RX_FIFO_WR_BIN];
    const word_t fifo_rd_bin = r[FIFO_RX_FIFO_RD_BIN];
    const word_t fifo_wr_gray = r[FIFO_RX_FIFO_WR_GRAY];
    const word_t fifo_rd_gray = r[FIFO_RX_FIFO_RD_GRAY];
    const word_t fifo_wq1_rgray = r[FIFO_RX_FIFO_WQ1_RGRAY];
    const word_t fifo_wq2_rgray = r[FIFO_RX_FIFO_WQ2_RGRAY];
    const word_t fifo_rq1_wgray = r[FIFO_RX_FIFO_RQ1_WGRAY];
    const word_t fifo_rq2_wgray = r[FIFO_RX_FIFO_RQ2_WGRAY];
    const word_t fifo_full = r[FIFO_RX_FIFO_FULL];
    const word_t fifo_empty = r[FIFO_RX_FIFO_EMPTY];
    const word_t fifo_wr_fire = r[FIFO_RX_FIFO_WR_FIRE];
    const word_t fifo_rd_fire = r[FIFO_RX_FIFO_RD_FIRE];
    const word_t fifo_last_bid_px = r[FIFO_RX_FIFO_LAST_BID_PX];
    const word_t fifo_last_ask_px = r[FIFO_RX_FIFO_LAST_ASK_PX];
    const word_t fifo_last_time = r[FIFO_RX_FIFO_LAST_TIME];
    const word_t fifo_last_src_time = r[FIFO_RX_FIFO_LAST_SRC_TIME];
    const word_t fifo_last_symbol = r[FIFO_RX_FIFO_LAST_SYMBOL];
    const word_t fifo_last_pip = r[FIFO_RX_FIFO_LAST_PIP];
    const word_t fifo_last_commission = r[FIFO_RX_FIFO_LAST_COMMISSION];
    const word_t fifo_last_seq = r[FIFO_RX_FIFO_LAST_SEQ];

    /* COMPUTE phase — combinational cell chain (declaration order). */
    const word_t wr_idx = cell_and(fifo_wr_bin, slot_mask);
    const word_t empty = cell_eqmask(fifo_rd_gray, fifo_rq2_wgray);
    const word_t full_cmp = cell_xor(fifo_wq2_rgray, top2_mask);
    const word_t full = cell_eqmask(fifo_wr_gray, full_cmp);
    const word_t nfull = cell_not(full);
    const word_t wr_fire = cell_and(nic_seam_strobe, nfull);
    const word_t nempty = cell_not(empty);
    const word_t rd_fire = cell_and(fifo_rd_en, nempty);
    const word_t wr_bin_n = cell_addsub(fifo_wr_bin, wr_fire, 0ULL);
    const word_t rd_bin_n = cell_addsub(fifo_rd_bin, rd_fire, 0ULL);
    const word_t wg_sar = cell_sar(cell_addsub(wr_bin_n, zero, 0ULL), 1u);
    const word_t wg_lsr = cell_and(wg_sar, lmask_1);
    const word_t wr_gray_n = cell_xor(wr_bin_n, wg_lsr);
    const word_t rg_sar = cell_sar(cell_addsub(rd_bin_n, zero, 0ULL), 1u);
    const word_t rg_lsr = cell_and(rg_sar, lmask_1);
    const word_t rd_gray_n = cell_xor(rd_bin_n, rg_lsr);
    const word_t wq1_n = cell_mux(fifo_wq1_rgray, fifo_rd_gray, fifo_power);
    const word_t wq2_n = cell_mux(fifo_wq2_rgray, fifo_wq1_rgray, fifo_power);
    const word_t rq1_n = cell_mux(fifo_rq1_wgray, fifo_wr_gray, fifo_power);
    const word_t rq2_n = cell_mux(fifo_rq2_wgray, fifo_rq1_wgray, fifo_power);
    const word_t step = cell_gate(one, fifo_power);
    const word_t ticks_next = cell_addsub(fifo_ticks, step, 0ULL);
    const word_t last_bid_px_buf = cell_buf(nic_seam_bid_px);
    const word_t last_ask_px_buf = cell_buf(nic_seam_ask_px);
    const word_t last_time_buf = cell_buf(nic_seam_time);
    const word_t last_src_time_buf = cell_buf(nic_seam_src_time);
    const word_t last_symbol_buf = cell_buf(nic_seam_symbol);
    const word_t last_pip_buf = cell_buf(nic_seam_pip);
    const word_t last_commission_buf = cell_buf(nic_seam_commission);
    const word_t last_seq_buf = cell_buf(nic_seam_seq);

    /* WRITE phase — gated dff commit: r[X] = cell_dff(q, fed_by, enable). */
    r[FIFO_RX_FIFO_TICKS] = cell_dff(fifo_ticks, ticks_next, one);
    r[FIFO_RX_FIFO_WR_BIN] = cell_dff(fifo_wr_bin, wr_bin_n, one);
    r[FIFO_RX_FIFO_RD_BIN] = cell_dff(fifo_rd_bin, rd_bin_n, one);
    r[FIFO_RX_FIFO_WR_GRAY] = cell_dff(fifo_wr_gray, wr_gray_n, one);
    r[FIFO_RX_FIFO_RD_GRAY] = cell_dff(fifo_rd_gray, rd_gray_n, one);
    r[FIFO_RX_FIFO_WQ1_RGRAY] = cell_dff(fifo_wq1_rgray, wq1_n, one);
    r[FIFO_RX_FIFO_WQ2_RGRAY] = cell_dff(fifo_wq2_rgray, wq2_n, one);
    r[FIFO_RX_FIFO_RQ1_WGRAY] = cell_dff(fifo_rq1_wgray, rq1_n, one);
    r[FIFO_RX_FIFO_RQ2_WGRAY] = cell_dff(fifo_rq2_wgray, rq2_n, one);
    r[FIFO_RX_FIFO_FULL] = cell_dff(fifo_full, full, one);
    r[FIFO_RX_FIFO_EMPTY] = cell_dff(fifo_empty, empty, one);
    r[FIFO_RX_FIFO_WR_FIRE] = cell_dff(fifo_wr_fire, wr_fire, one);
    r[FIFO_RX_FIFO_RD_FIRE] = cell_dff(fifo_rd_fire, rd_fire, one);
    r[FIFO_RX_FIFO_LAST_BID_PX] = cell_dff(fifo_last_bid_px, last_bid_px_buf, wr_fire);
    r[FIFO_RX_FIFO_LAST_ASK_PX] = cell_dff(fifo_last_ask_px, last_ask_px_buf, wr_fire);
    r[FIFO_RX_FIFO_LAST_TIME] = cell_dff(fifo_last_time, last_time_buf, wr_fire);
    r[FIFO_RX_FIFO_LAST_SRC_TIME] = cell_dff(fifo_last_src_time, last_src_time_buf, wr_fire);
    r[FIFO_RX_FIFO_LAST_SYMBOL] = cell_dff(fifo_last_symbol, last_symbol_buf, wr_fire);
    r[FIFO_RX_FIFO_LAST_PIP] = cell_dff(fifo_last_pip, last_pip_buf, wr_fire);
    r[FIFO_RX_FIFO_LAST_COMMISSION] = cell_dff(fifo_last_commission, last_commission_buf, wr_fire);
    r[FIFO_RX_FIFO_LAST_SEQ] = cell_dff(fifo_last_seq, last_seq_buf, wr_fire);
    r[FIFO_RX_WR_IDX] = wr_idx;
    r[FIFO_RX_EMPTY] = empty;
    r[FIFO_RX_FULL_CMP] = full_cmp;
    r[FIFO_RX_FULL] = full;
    r[FIFO_RX_NFULL] = nfull;
    r[FIFO_RX_WR_FIRE] = wr_fire;
    r[FIFO_RX_NEMPTY] = nempty;
    r[FIFO_RX_RD_FIRE] = rd_fire;
    r[FIFO_RX_WR_BIN_N] = wr_bin_n;
    r[FIFO_RX_RD_BIN_N] = rd_bin_n;
    r[FIFO_RX_WG_SAR] = wg_sar;
    r[FIFO_RX_WG_LSR] = wg_lsr;
    r[FIFO_RX_WR_GRAY_N] = wr_gray_n;
    r[FIFO_RX_RG_SAR] = rg_sar;
    r[FIFO_RX_RG_LSR] = rg_lsr;
    r[FIFO_RX_RD_GRAY_N] = rd_gray_n;
    r[FIFO_RX_WQ1_N] = wq1_n;
    r[FIFO_RX_WQ2_N] = wq2_n;
    r[FIFO_RX_RQ1_N] = rq1_n;
    r[FIFO_RX_RQ2_N] = rq2_n;
    r[FIFO_RX_STEP] = step;
    r[FIFO_RX_TICKS_NEXT] = ticks_next;
    r[FIFO_RX_LAST_BID_PX_BUF] = last_bid_px_buf;
    r[FIFO_RX_LAST_ASK_PX_BUF] = last_ask_px_buf;
    r[FIFO_RX_LAST_TIME_BUF] = last_time_buf;
    r[FIFO_RX_LAST_SRC_TIME_BUF] = last_src_time_buf;
    r[FIFO_RX_LAST_SYMBOL_BUF] = last_symbol_buf;
    r[FIFO_RX_LAST_PIP_BUF] = last_pip_buf;
    r[FIFO_RX_LAST_COMMISSION_BUF] = last_commission_buf;
    r[FIFO_RX_LAST_SEQ_BUF] = last_seq_buf;
    r[FIFO_RX_FIFO_EMPTY_OUT] = fifo_empty;
    r[FIFO_RX_FIFO_RD_FIRE_OUT] = fifo_rd_fire;

    { /* addressed RAM write port */
        const word_t _ram_wa = (wr_idx) & 511ULL;
        const word_t _ram_we = wr_fire;
        r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 0ULL] = cell_dff(r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 0ULL], nic_seam_bid_px, _ram_we);
        r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 1ULL] = cell_dff(r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 1ULL], nic_seam_ask_px, _ram_we);
        r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 2ULL] = cell_dff(r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 2ULL], nic_seam_time, _ram_we);
        r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 3ULL] = cell_dff(r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 3ULL], nic_seam_src_time, _ram_we);
        r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 4ULL] = cell_dff(r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 4ULL], nic_seam_symbol, _ram_we);
        r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 5ULL] = cell_dff(r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 5ULL], nic_seam_pip, _ram_we);
        r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 6ULL] = cell_dff(r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 6ULL], nic_seam_commission, _ram_we);
        r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 7ULL] = cell_dff(r[FIFO_RX_FIFO_SLOT_0_BID_PX + _ram_wa*8ULL + 7ULL], nic_seam_seq, _ram_we);
    }

}

/* fifo_rx_run: canonical free-running clock. Power on once; the clock
 * self-oscillates while the power bit is set. Nothing external steps it. */
static inline void fifo_rx_run(word_t *r) {
    while (r[FIFO_RX_FIFO_POWER] & 1ULL) { fifo_rx_tick(r); }
}

